class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int res = 0;
        for (int i = 0; i < n; i += k) {
            int[] cnt = new int[26];
            for (int j = i; j < Math.min(i + k, n); j++) {
                cnt[s.charAt(j) - 'a']++;
            }
            int maxCnt = 0;
            for (int j = 0; j < 26; j++) {
                maxCnt = Math.max(maxCnt, cnt[j]);
            }
            res += Math.min(i + k, n) - i - maxCnt;
        }
        return res;
    }
}
